function CameraGrabber({ targetRef }: { targetRef: React.MutableRefObject<THREE.Camera | null> }) {
  const { camera } = useThree();
  useEffect(() => { targetRef.current = camera; }, [camera, targetRef]);
  return null;
}

function PCBComponent({ label }: { label: string }) {
  switch (label) {
    case "Resistor":   return <Resistor />;
    case "Capacitor":  return <Capacitor />;
    case "Diode":      return <Diode />;
    case "LED":        return <LED />;
    case "Transistor": return <Transistor />;
    case "IC":         return <IC />;
    case "Inductor":   return <Inductor />;
    case "Crystal":    return <Crystal />;
    case "Switch":     return <Switch />;
    case "Header":     return <Header />;
    default:           return <GenericComponent label={label} />;
  }
}


function GhostPCBComponent({ label }: { label: string }) {
  const groupRef = useRef<THREE.Group>(null);
  useEffect(() => {
    if (!groupRef.current) return;
    groupRef.current.traverse((child) => {
      if ((child as THREE.Mesh).isMesh) {
        const mesh = child as THREE.Mesh;
        const orig = Array.isArray(mesh.material) ? mesh.material[0] : mesh.material;
        const mat  = (orig as THREE.MeshStandardMaterial).clone();
        mat.transparent      = true;
        mat.opacity          = 0.5;
        mat.emissive         = new THREE.Color(0x003344);
        mat.emissiveIntensity = 0.5;
        mat.depthWrite       = false;
        mesh.material = mat;
      }
    });
  }, [label]);
  return <group ref={groupRef}><PCBComponent label={label} /></group>;
}





